import{c as a,Q as s,j as t,m as o}from"./chunks/framework.CTNaDwNv.js";const h=JSON.parse('{"title":"ACE permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ace.md","filePath":"guide/ace.md","lastUpdated":1779853631000}'),n={name:"guide/ace.md"};function d(i,e,c,r,l,p){return s(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="ace-permissions" tabindex="-1">ACE permissions <a class="header-anchor" href="#ace-permissions" aria-label="Permalink to &quot;ACE permissions&quot;">​</a></h1><p>FiveM gates console commands behind ACEs (Access Control Entries). When <code>agent_api</code> calls <code>ExecuteCommand(&quot;ensure foo&quot;)</code>, FiveM checks whether the <strong>agent_api resource itself</strong> has permission to run <code>ensure</code>. By default it does not.</p><p>If you skip this step, every lifecycle call will log:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[cmd] Access denied for command ensure.</span></span></code></pre></div><h2 id="required-aces" tabindex="-1">Required ACEs <a class="header-anchor" href="#required-aces" aria-label="Permalink to &quot;Required ACEs&quot;">​</a></h2><p>Add to <code>server.cfg</code> and restart the server (<code>refresh</code> is not enough for ACEs):</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add_ace resource.agent_api command.ensure  allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.start   allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.stop    allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.restart allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.refresh allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.say     allow</span></span></code></pre></div><h2 id="looser-variant" tabindex="-1">Looser variant <a class="header-anchor" href="#looser-variant" aria-label="Permalink to &quot;Looser variant&quot;">​</a></h2><p>If maintaining six lines feels tedious and you trust the agent_api resource fully, grant every command:</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add_ace resource.agent_api command allow</span></span></code></pre></div><p>Tradeoff: agent_api can now invoke any console command via <code>run_command</code>, including ones we don&#39;t expose (because the <code>run_command</code> allowlist is independent of FiveM&#39;s ACE — but if you later widen the agent_api allowlist, your blast radius is bigger).</p><h2 id="other-aces-you-might-want" tabindex="-1">Other ACEs you might want <a class="header-anchor" href="#other-aces-you-might-want" aria-label="Permalink to &quot;Other ACEs you might want&quot;">​</a></h2><p>These are not required by default but make sense if you grow the resource:</p><table tabindex="0"><thead><tr><th>ACE</th><th>When you&#39;d add it</th></tr></thead><tbody><tr><td><code>command.kick allow</code></td><td>If you add a tool that calls FiveM&#39;s <code>kick</code></td></tr><tr><td><code>command.acl allow</code></td><td>If you add ACL management tools</td></tr><tr><td><code>webadmin allow</code></td><td>If you expose admin endpoints</td></tr></tbody></table><p><code>agent_api</code> ships with <strong>none</strong> of these enabled and refuses to add <code>add_ace</code> itself — only the operator (you) can change permissions.</p>`,15)])])}const m=a(n,[["render",d]]);export{h as __pageData,m as default};
